// AUDIO CONSTANTS
// ============================================================
const AUDIO_MAP = {
  red: "data:audio/mpeg;base64,",
  yellow: "data:audio/mpeg;base64,",
  green: "data:audio/mpeg;base64,",
};

let currentAudio = null;

function playFlagAudio(classification) {
  if (currentAudio) {
    currentAudio.pause();
    currentAudio.currentTime = 0;
  }
  const src = AUDIO_MAP[classification];
  if (src) {
    currentAudio = new Audio(src);
    currentAudio.volume = 0.7;
    currentAudio.play().catch(() => {});
  }
}

// ============================================================
// SCORING ENGINE
// ============================================================
const scoringEngine = {
  // Self-assessment questions
  selfAssessmentQuestions: [
    { id: 1, category: "Communication", text: "When my partner/interest doesn't text back quickly, I:", options: ["Wait patiently and continue my day", "Check their online status occasionally", "Send follow-up messages after an hour", "Send multiple messages and feel anxious"], weights: [0, 1, 2, 4] },
    { id: 2, category: "Communication", text: "During arguments, I typically:", options: ["Listen actively and express my feelings calmly", "Get defensive but come around eventually", "Raise my voice or use harsh language", "Give silent treatment or stonewall"], weights: [0, 1, 3, 4] },
    { id: 3, category: "Communication", text: "When I disagree with my partner, I:", options: ["Have a calm discussion about our differences", "Argue my point but respect theirs too", "Try to convince them I'm right at all costs", "Get manipulative or emotional to win"], weights: [0, 1, 3, 4] },
    { id: 4, category: "Emotional Maturity", text: "When I'm upset about something unrelated, I:", options: ["Process it separately and communicate if needed", "Bring some mood home but don't blame my partner", "Take it out on my partner without realizing it", "Intentionally make my partner feel responsible"], weights: [0, 1, 3, 4] },
    { id: 5, category: "Emotional Maturity", text: "How do you handle your partner having a bad day?", options: ["Offer support and give space when needed", "Try to help, sometimes get frustrated", "Make it about me if I had a worse day", "Compete with their problems or dismiss them"], weights: [0, 1, 3, 4] },
    { id: 6, category: "Emotional Maturity", text: "When I feel insecure in a relationship, I:", options: ["Communicate my needs clearly", "Seek reassurance occasionally", "Test my partner's loyalty subtly", "Sabotage things before I get hurt"], weights: [0, 1, 3, 4] },
    { id: 7, category: "Accountability", text: "When I'm clearly wrong in a disagreement, I:", options: ["Admit it immediately and apologize genuinely", "Admit it eventually after some resistance", "Admit it only if pushed hard enough", "Rarely or never admit fault"], weights: [0, 1, 3, 4] },
    { id: 8, category: "Accountability", text: "After hurting someone, my apology is usually:", options: ["Sincere, specific, and I change my behavior", "Genuine but I might repeat it", "Mostly to end the conflict", "I rarely feel I owe one"], weights: [0, 1, 3, 4] },
    { id: 9, category: "Accountability", text: "When a relationship ends, I:", options: ["Reflect on my role and grow from it", "Mostly see their faults but acknowledge mine", "Blame my ex almost entirely", "Never see myself as part of the problem"], weights: [0, 1, 3, 4] },
    { id: 10, category: "Jealousy", text: "When my partner talks to attractive people, I:", options: ["Feel secure and trust them completely", "Notice slight discomfort but don't act on it", "Bring it up later with some frustration", "Confront them or create scenes"], weights: [0, 1, 3, 4] },
    { id: 11, category: "Jealousy", text: "I check my partner's phone or social media:", options: ["Never — I respect their privacy fully", "Rarely, usually when something feels off", "Occasionally when I feel insecure", "Regularly to make sure nothing is wrong"], weights: [0, 1, 3, 4] },
    { id: 12, category: "Jealousy", text: "When my partner spends time with friends, I:", options: ["Encourage it and enjoy my own time", "Miss them but support it", "Get resentful if it's frequent", "Try to limit their social time"], weights: [0, 1, 3, 4] },
    { id: 13, category: "Consistency", text: "How consistent are you with your promises?", options: ["I follow through almost always", "I follow through most of the time", "I forget or cancel more than I'd like", "My words and actions often don't match"], weights: [0, 1, 3, 4] },
    { id: 14, category: "Consistency", text: "My mood and affection toward partners is:", options: ["Steady and predictable even through stress", "Generally stable with some variation", "Quite variable depending on my mood", "Unpredictable — hot and cold"], weights: [0, 1, 3, 4] },
    { id: 15, category: "Consistency", text: "At the start vs. now, my effort level is:", options: ["I maintain the same energy throughout", "Slightly lower but still solid", "Noticeably less than at the start", "I put in much less effort over time"], weights: [0, 1, 3, 4] },
    { id: 16, category: "Boundaries", text: "When a partner sets a boundary I disagree with, I:", options: ["Respect it completely even if it's hard", "Accept it but might discuss why I disagree", "Push back and test if they're serious", "Ignore or repeatedly cross it"], weights: [0, 1, 3, 4] },
    { id: 17, category: "Boundaries", text: "My own personal boundaries in relationships are:", options: ["Clear, communicated, and maintained", "Somewhat defined but often get blurred", "Unclear — I struggle to set them", "Nonexistent — I give everything and resent it"], weights: [0, 1, 3, 4] },
    { id: 18, category: "Boundaries", text: "When someone needs space, I:", options: ["Respect it fully without taking it personally", "Give it but check in occasionally", "Find it very difficult and reach out anyway", "Take it as rejection and escalate"], weights: [0, 1, 3, 4] },
    { id: 19, category: "Communication", text: "In relationships, I share my feelings:", options: ["Openly and at the right time", "When asked or when necessary", "Rarely — I prefer to keep it inside", "Never — I avoid emotional conversations"], weights: [0, 1, 3, 4] },
    { id: 20, category: "Emotional Maturity", text: "My past relationships have taught me:", options: ["A lot — I've grown significantly", "Some lessons I've applied", "I recognize patterns but struggle to change", "Nothing — the problem is always others"], weights: [0, 1, 3, 4] },
    { id: 21, category: "Accountability", text: "When I say something hurtful, I:", options: ["Recognize it quickly and make it right", "Realize later and apologize", "Wait for them to bring it up first", "Double down or justify what I said"], weights: [0, 1, 3, 4] },
    { id: 22, category: "Jealousy", text: "My partner having close friends of genders I'm attracted to makes me:", options: ["Comfortable — I trust them fully", "Slightly alert but I manage it well", "Uncomfortable and I show it sometimes", "Very jealous and I act on it"], weights: [0, 1, 3, 4] },
    { id: 23, category: "Consistency", text: "When I'm not interested in someone anymore, I:", options: ["Have an honest conversation about it", "Start slowly pulling back and eventually talk", "Ghost or fade out gradually", "Ignore or string them along"], weights: [0, 1, 3, 4] },
    { id: 24, category: "Boundaries", text: "I use guilt or emotional pressure in relationships:", options: ["Never", "Very rarely, only if desperate", "Sometimes when I feel ignored", "Often — it usually works for me"], weights: [0, 1, 3, 4] },
    { id: 25, category: "Communication", text: "When I need something from a partner, I:", options: ["Ask directly and clearly", "Hint and hope they notice", "Wait until I'm resentful then bring it up", "Expect them to just know and get hurt if they don't"], weights: [0, 1, 3, 4] },
  ],

  calculateSelfScore(answers) {
    const categories = {};
    const maxPerQ = 4;

    this.selfAssessmentQuestions.forEach((q, i) => {
      const cat = q.category;
      if (!categories[cat]) categories[cat] = { score: 0, max: 0, count: 0 };
      categories[cat].score += answers[i] ?? 0;
      categories[cat].max += maxPerQ;
      categories[cat].count++;
    });

    const catScores = {};
    let totalScore = 0;
    let totalMax = 0;

    Object.entries(categories).forEach(([cat, data]) => {
      const pct = Math.round((data.score / data.max) * 100);
      catScores[cat] = pct;
      totalScore += data.score;
      totalMax += data.max;
    });

    const overall = Math.round((totalScore / totalMax) * 100);
    let classification = "green";
    if (overall > 50) classification = "red";
    else if (overall > 25) classification = "yellow";

    return { catScores, overall, classification };
  },

  // Partner assessment scoring
  calculatePartnerScore(factors) {
    const weights = {
      communication: 0.2,
      emotionalMaturity: 0.2,
      consistency: 0.2,
      boundaryRespect: 0.2,
      accountability: 0.2,
    };
    let total = 0;
    Object.entries(weights).forEach(([key, w]) => {
      total += (factors[key] ?? 50) * w;
    });
    return Math.round(total);
  },

  // Interest probability
  calculateInterest(factors) {
    const w = { initiation: 0.25, responseTime: 0.2, effort: 0.25, futurePlanning: 0.15, vulnerability: 0.15 };
    let score = 0;
    Object.entries(w).forEach(([k, wt]) => score += (factors[k] ?? 50) * wt);
    return Math.round(score);
  },

  // Relationship type
  classifyRelationship(data) {
    const types = [
      { name: "Healthy", threshold: (d) => d.commitment >= 70 && d.reciprocity >= 65 && d.stability >= 60 },
      { name: "Love Bombing", threshold: (d) => d.intensity >= 80 && d.consistency < 40 },
      { name: "Situationship", threshold: (d) => d.commitment < 40 && d.reciprocity >= 50 && d.ambiguity >= 60 },
      { name: "Benching", threshold: (d) => d.availability < 40 && d.interest >= 50 },
      { name: "Rebound", threshold: (d) => d.recentBreakup >= 70 && d.intensity >= 60 },
      { name: "Flirtationship", threshold: (d) => d.physical >= 60 && d.commitment < 30 && d.emotional < 40 },
      { name: "One-Sided", threshold: (d) => d.reciprocity < 35 },
      { name: "Casual", threshold: (d) => d.commitment < 40 && d.physical >= 50 && d.emotional < 50 },
    ];

    const matches = types.filter(t => t.threshold(data));
    return {
      primary: matches[0]?.name ?? "Undefined",
      secondary: matches[1]?.name ?? null,
    };
  }
};

// ============================================================
// AI SERVICE
// ============================================================
async function callAI(prompt, brutal = false) {
  const toneInstruction = brutal
    ? "Be brutally honest, direct, sharp, and slightly confrontational. Don't sugarcoat anything. Call out patterns clearly. Be psychologically precise but with a sharp edge."
    : "Be calm, psychologically grounded, neutral in tone, and supportive while being honest.";

  const systemPrompt = `You are FlagLogic AI, a relationship intelligence engine. ${toneInstruction} 
Keep responses concise (3-5 sentences max). Use psychological terminology. Be insightful, not generic. 
Format: Start with a punchy observation, then elaborate, end with a clear action or insight.`;

  try {
    const response = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        model: "claude-sonnet-4-20250514",
        max_tokens: 1000,
        system: systemPrompt,
        messages: [{ role: "user", content: prompt }],
      }),
    });
    const data = await response.json();
    return data.content?.[0]?.text ?? "Analysis unavailable.";
  } catch (e) {
    return "AI analysis temporarily unavailable.";
  }
}

