// Radar Chart
function RadarChart({ data, size = 260 }) {
  const categories = Object.keys(data);
  const n = categories.length;
  const center = size / 2;
  const radius = size * 0.38;
  const angleStep = (Math.PI * 2) / n;

  const getPoint = (i, r) => ({
    x: center + r * Math.cos(i * angleStep - Math.PI / 2),
    y: center + r * Math.sin(i * angleStep - Math.PI / 2),
  });

  const levels = [0.25, 0.5, 0.75, 1];
  const colors = { Communication: "#6366f1", "Emotional Maturity": "#8b5cf6", Accountability: "#22c55e", Jealousy: "#ef4444", Consistency: "#eab308", Boundaries: "#06b6d4" };

  const dataPoints = categories.map((cat, i) => {
    const val = data[cat] / 100;
    return getPoint(i, val * radius);
  });

  const pathD = dataPoints.map((p, i) => `${i === 0 ? "M" : "L"}${p.x},${p.y}`).join(" ") + "Z";

  return (
    <svg width={size} height={size} style={{ overflow: "visible" }}>
      {levels.map(l => {
        const pts = categories.map((_, i) => getPoint(i, l * radius));
        return <polygon key={l} points={pts.map(p => `${p.x},${p.y}`).join(" ")} fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth="1" />;
      })}
      {categories.map((_, i) => {
        const pt = getPoint(i, radius);
        return <line key={i} x1={center} y1={center} x2={pt.x} y2={pt.y} stroke="rgba(255,255,255,0.06)" strokeWidth="1" />;
      })}
      <path d={pathD} fill="rgba(99,102,241,0.15)" stroke="#6366f1" strokeWidth="2" strokeLinejoin="round" />
      {dataPoints.map((p, i) => (
        <circle key={i} cx={p.x} cy={p.y} r="4" fill={colors[categories[i]] ?? "#6366f1"} stroke="#080b10" strokeWidth="2" />
      ))}
      {categories.map((cat, i) => {
        const pt = getPoint(i, radius + 28);
        return (
          <text key={i} x={pt.x} y={pt.y} textAnchor="middle" dominantBaseline="middle"
            fill="rgba(255,255,255,0.6)" fontSize="11" fontFamily="'DM Sans', sans-serif" fontWeight="500">
            {cat.split(" ").map((w, j) => (
              <tspan key={j} x={pt.x} dy={j === 0 ? (cat.includes(" ") ? "-6" : "0") : "13"}>{w}</tspan>
            ))}
          </text>
        );
      })}
    </svg>
  );
}

// Animated Gauge (semicircle)
function SemiGauge({ value, color, label, size = 180 }) {
  const r = 70;
  const cx = size / 2;
  const cy = size * 0.7;
  const circumference = Math.PI * r;
  const offset = circumference - (value / 100) * circumference;

  const getColor = () => {
    if (value < 33) return "#22c55e";
    if (value < 66) return "#eab308";
    return "#ef4444";
  };
  const c = color || getColor();

  return (
    <div style={{ textAlign: "center" }}>
      <svg width={size} height={size * 0.65} style={{ overflow: "visible" }}>
        <path d={`M ${cx - r} ${cy} A ${r} ${r} 0 0 1 ${cx + r} ${cy}`}
          fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth="10" strokeLinecap="round" />
        <path d={`M ${cx - r} ${cy} A ${r} ${r} 0 0 1 ${cx + r} ${cy}`}
          fill="none" stroke={c} strokeWidth="10" strokeLinecap="round"
          strokeDasharray={circumference} strokeDashoffset={offset}
          style={{ transition: "stroke-dashoffset 1.2s cubic-bezier(0.4,0,0.2,1)", filter: `drop-shadow(0 0 8px ${c}60)` }} />
        <text x={cx} y={cy - 8} textAnchor="middle" fill={c} fontSize="28" fontWeight="800" fontFamily="'Syne', sans-serif">{value}%</text>
        {label && <text x={cx} y={cy + 12} textAnchor="middle" fill="rgba(255,255,255,0.4)" fontSize="11" fontFamily="'DM Sans', sans-serif">{label}</text>}
      </svg>
    </div>
  );
}

// Progress Bar
function ProgressBar({ value, color, label, showValue = true }) {
  const getColor = () => {
    if (!color) {
      if (value < 33) return "#22c55e";
      if (value < 66) return "#eab308";
      return "#ef4444";
    }
    return color;
  };

  return (
    <div style={{ marginBottom: "12px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "6px" }}>
        <span style={{ fontSize: "13px", color: "rgba(255,255,255,0.6)" }}>{label}</span>
        {showValue && <span style={{ fontSize: "13px", color: getColor(), fontWeight: "600" }}>{value}%</span>}
      </div>
      <div style={{ height: "6px", background: "rgba(255,255,255,0.06)", borderRadius: "99px", overflow: "hidden" }}>
        <div style={{
          height: "100%", width: `${value}%`, borderRadius: "99px",
          background: `linear-gradient(90deg, ${getColor()}88, ${getColor()})`,
          boxShadow: `0 0 8px ${getColor()}40`,
          transition: "width 1s cubic-bezier(0.4,0,0.2,1)",
          animation: "progress-fill 1s cubic-bezier(0.4,0,0.2,1)"
        }} />
      </div>
    </div>
  );
}

// Flag Badge
function FlagBadge({ classification, size = "md" }) {
  const config = {
    green: { emoji: "🟢", label: "Green Flag", color: "#22c55e", bg: "rgba(34,197,94,0.1)" },
    yellow: { emoji: "🟡", label: "Yellow Flag", color: "#eab308", bg: "rgba(234,179,8,0.1)" },
    red: { emoji: "🔴", label: "Red Flag", color: "#ef4444", bg: "rgba(239,68,68,0.1)" },
  };
  const c = config[classification] ?? config.yellow;
  const fontSize = size === "lg" ? "16px" : "13px";
  const padding = size === "lg" ? "10px 20px" : "6px 14px";

  return (
    <span style={{
      display: "inline-flex", alignItems: "center", gap: "6px",
      padding, borderRadius: "99px", background: c.bg,
      border: `1px solid ${c.color}30`, color: c.color,
      fontWeight: "600", fontSize, fontFamily: "'Syne', sans-serif",
    }}>
      {c.emoji} {c.label}
    </span>
  );
}

// AI Result Box
function AIBox({ text, brutal, loading }) {
  if (!text && !loading) return null;
  return (
    <div style={{
      marginTop: "20px", padding: "18px 20px",
      background: brutal ? "rgba(239,68,68,0.05)" : "rgba(99,102,241,0.05)",
      border: `1px solid ${brutal ? "rgba(239,68,68,0.2)" : "rgba(99,102,241,0.2)"}`,
      borderRadius: "12px", position: "relative", overflow: "hidden",
    }}>
      <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "10px" }}>
        <span style={{ fontSize: "18px" }}>{brutal ? "🔥" : "🤖"}</span>
        <span style={{ fontSize: "12px", fontWeight: "600", color: brutal ? "#ef4444" : "#6366f1", textTransform: "uppercase", letterSpacing: "1px" }}>
          {brutal ? "Brutal Mode Analysis" : "AI Analysis"}
        </span>
      </div>
      {loading ? (
        <div style={{ display: "flex", alignItems: "center", gap: "10px", color: "rgba(255,255,255,0.4)" }}>
          <div style={{ width: "16px", height: "16px", border: "2px solid rgba(99,102,241,0.3)", borderTop: "2px solid #6366f1", borderRadius: "50%", animation: "spin 0.8s linear infinite" }} />
          <span style={{ fontSize: "14px" }}>Analyzing patterns...</span>
        </div>
      ) : (
        <p style={{ fontSize: "14px", lineHeight: "1.7", color: "rgba(255,255,255,0.75)", fontStyle: "italic" }}>{text}</p>
      )}
    </div>
  );
}

// Card wrapper
