// ADVANCED FEATURES
// ============================================================
function AdvancedTools({ brutal }) {
  const [activeTool, setActiveTool] = useState(null);
  const [inputs, setInputs] = useState({
    consistency: 50, emotionalMaturity: 50, commitment: 50, reciprocity: 50, rebound: 20,
    commAlign: 50, attachCompat: 50, conflictRes: 50, emotNeeds: 50, valueAlign: 50,
    ghosting: 30, burnout: 40, commitAvoid: 35, drama: 25,
    stability: 60, emotionalAlign: 55, trust: 65, risk: 35,
  });
  const [result, setResult] = useState(null);
  const [aiText, setAiText] = useState("");
  const [aiLoading, setAiLoading] = useState(false);

  const tools = [
    { id: "future", emoji: "🔮", label: "Future Prediction" },
    { id: "compat", emoji: "🤝", label: "Compatibility Score" },
    { id: "situRisk", emoji: "🛑", label: "Situationship Risk" },
    { id: "willwork", emoji: "📊", label: "Will This Work?" },
  ];

  const compute = async (toolId) => {
    let res = {};
    let prompt = "";
    if (toolId === "future") {
      const base = (inputs.consistency + inputs.emotionalMaturity + inputs.commitment + inputs.reciprocity) / 4;
      res = {
        oneMonth: Math.round(Math.min(95, base + Math.random() * 5 - 2)),
        threeMonth: Math.round(Math.min(90, base - 5 + Math.random() * 8)),
        sixMonth: Math.round(Math.min(85, base - 12 + Math.random() * 10)),
      };
      prompt = `Relationship future prediction. 1-month positive outcome: ${res.oneMonth}%, 3-month: ${res.threeMonth}%, 6-month: ${res.sixMonth}%. Based on consistency ${inputs.consistency}%, emotional maturity ${inputs.emotionalMaturity}%, commitment ${inputs.commitment}%, reciprocity ${inputs.reciprocity}%. Give a timeline forecast.`;
    } else if (toolId === "compat") {
      res.score = Math.round((inputs.commAlign + inputs.attachCompat + inputs.conflictRes + inputs.emotNeeds + inputs.valueAlign) / 5);
      const all = [["Communication Alignment", inputs.commAlign], ["Attachment Compatibility", inputs.attachCompat], ["Conflict Resolution", inputs.conflictRes], ["Emotional Needs", inputs.emotNeeds], ["Value Alignment", inputs.valueAlign]];
      res.strengths = all.filter(([, v]) => v >= 65).map(([k]) => k);
      res.frictions = all.filter(([, v]) => v < 45).map(([k]) => k);
      prompt = `Compatibility analysis: overall ${res.score}%. Strengths: ${res.strengths.join(", ")}. Friction zones: ${res.frictions.join(", ")}. Give compatibility insight.`;
    } else if (toolId === "situRisk") {
      res = { ghosting: inputs.ghosting, burnout: inputs.burnout, commitAvoid: inputs.commitAvoid, drama: inputs.drama };
      prompt = `Situationship risk meter: Ghosting risk ${inputs.ghosting}%, Burnout risk ${inputs.burnout}%, Commitment avoidance ${inputs.commitAvoid}%, Drama probability ${inputs.drama}%. Analyze these risks.`;
    } else if (toolId === "willwork") {
      res.score = Math.round((inputs.stability + inputs.emotionalAlign + inputs.trust + (100 - inputs.risk)) / 4);
      prompt = `Long-term viability analysis: stability ${inputs.stability}%, emotional alignment ${inputs.emotionalAlign}%, trust ${inputs.trust}%, risk score ${inputs.risk}%. Overall viability: ${res.score}%. Will this relationship work long-term?`;
    }
    setResult({ toolId, ...res });
    setAiLoading(true);
    const t = await callAI(prompt, brutal);
    setAiText(t);
    setAiLoading(false);
  };

  const sliders = {
    future: [
      { key: "consistency", label: "Consistency Trend" },
      { key: "emotionalMaturity", label: "Emotional Maturity" },
      { key: "commitment", label: "Commitment Alignment" },
      { key: "reciprocity", label: "Reciprocity Score" },
    ],
    compat: [
      { key: "commAlign", label: "Communication Alignment" },
      { key: "attachCompat", label: "Attachment Compatibility" },
      { key: "conflictRes", label: "Conflict Resolution" },
      { key: "emotNeeds", label: "Emotional Needs Alignment" },
      { key: "valueAlign", label: "Value Alignment" },
    ],
    situRisk: [
      { key: "ghosting", label: "Ghosting Risk" },
      { key: "burnout", label: "Emotional Burnout Risk" },
      { key: "commitAvoid", label: "Commitment Avoidance" },
      { key: "drama", label: "Drama Probability" },
    ],
    willwork: [
      { key: "stability", label: "Stability Index" },
      { key: "emotionalAlign", label: "Emotional Alignment" },
      { key: "trust", label: "Trust Score" },
      { key: "risk", label: "Risk Score (lower = better)" },
    ],
  };

  return (
    <div style={{ animation: "fadeUp 0.5s ease" }}>
      <SectionHeader emoji="🔮" title="Advanced Intelligence" subtitle="Predictive models & compatibility engines" color="#6366f1" />
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: "12px", marginBottom: "24px" }}>
        {tools.map(t => (
          <button key={t.id} onClick={() => { setActiveTool(t.id); setResult(null); setAiText(""); }}
            style={{
              padding: "16px", borderRadius: "12px", textAlign: "center", cursor: "pointer",
              background: activeTool === t.id ? "rgba(99,102,241,0.15)" : "var(--surface)",
              border: `1px solid ${activeTool === t.id ? "rgba(99,102,241,0.4)" : "var(--border)"}`,
              color: activeTool === t.id ? "#6366f1" : "rgba(255,255,255,0.6)",
              fontFamily: "'Syne', sans-serif", fontWeight: "600", transition: "all 0.2s",
            }}>
            <div style={{ fontSize: "28px", marginBottom: "8px" }}>{t.emoji}</div>
            <div style={{ fontSize: "12px" }}>{t.label}</div>
          </button>
        ))}
      </div>

      {activeTool && (
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "20px", animation: "fadeUp 0.4s ease" }}>
          <Card>
            <h4 style={{ fontFamily: "'Syne', sans-serif", marginBottom: "20px", fontSize: "14px", color: "var(--text-dim)", textTransform: "uppercase", letterSpacing: "1px" }}>
              {tools.find(t => t.id === activeTool)?.label}
            </h4>
            {(sliders[activeTool] ?? []).map(s => (
              <Slider key={s.key} label={s.label} value={inputs[s.key]} onChange={v => setInputs(i => ({ ...i, [s.key]: v }))} color="#6366f1" />
            ))}
            <Btn onClick={() => compute(activeTool)} size="lg" style={{ width: "100%", marginTop: "8px" }}>Calculate</Btn>
          </Card>

          <div>
            {result && result.toolId === activeTool ? (
              <div style={{ animation: "fadeUp 0.4s ease" }}>
                {activeTool === "future" && (
                  <Card style={{ marginBottom: "16px" }}>
                    <h4 style={{ fontFamily: "'Syne', sans-serif", marginBottom: "18px", color: "#6366f1" }}>Outcome Timeline</h4>
                    <ProgressBar label="1 Month Positive Outcome" value={result.oneMonth} color="#22c55e" />
                    <ProgressBar label="3 Month Positive Outcome" value={result.threeMonth} color="#eab308" />
                    <ProgressBar label="6 Month Positive Outcome" value={result.sixMonth} color="#f97316" />
                  </Card>
                )}
                {activeTool === "compat" && (
                  <Card style={{ marginBottom: "16px" }}>
                    <SemiGauge value={result.score} color="#6366f1" label="Compatibility" />
                    {result.strengths?.length > 0 && (
                      <div style={{ marginTop: "12px" }}>
                        <p style={{ fontSize: "12px", color: "#22c55e", marginBottom: "6px", textTransform: "uppercase", letterSpacing: "1px" }}>✅ Strength Zones</p>
                        {result.strengths.map(s => <div key={s} style={{ fontSize: "13px", color: "rgba(255,255,255,0.6)", padding: "3px 0" }}>• {s}</div>)}
                      </div>
                    )}
                    {result.frictions?.length > 0 && (
                      <div style={{ marginTop: "12px" }}>
                        <p style={{ fontSize: "12px", color: "#ef4444", marginBottom: "6px", textTransform: "uppercase", letterSpacing: "1px" }}>⚡ Friction Zones</p>
                        {result.frictions.map(s => <div key={s} style={{ fontSize: "13px", color: "rgba(255,255,255,0.6)", padding: "3px 0" }}>• {s}</div>)}
                      </div>
                    )}
                  </Card>
                )}
                {activeTool === "situRisk" && (
                  <Card style={{ marginBottom: "16px" }}>
                    <h4 style={{ fontFamily: "'Syne', sans-serif", marginBottom: "18px", color: "#ef4444" }}>Risk Analysis</h4>
                    <ProgressBar label="Ghosting Risk" value={result.ghosting} />
                    <ProgressBar label="Emotional Burnout" value={result.burnout} />
                    <ProgressBar label="Commitment Avoidance" value={result.commitAvoid} />
                    <ProgressBar label="Drama Probability" value={result.drama} />
                  </Card>
                )}
                {activeTool === "willwork" && (
                  <Card style={{ marginBottom: "16px", textAlign: "center" }}>
                    <SemiGauge value={result.score} label="Long-term Viability" />
                  </Card>
                )}
                <AIBox text={aiText} brutal={brutal} loading={aiLoading} />
              </div>
            ) : (
              <Card style={{ display: "flex", alignItems: "center", justifyContent: "center", minHeight: "250px", opacity: 0.4 }}>
                <div style={{ textAlign: "center" }}>
                  <div style={{ fontSize: "48px", marginBottom: "12px" }}>📊</div>
                  <p style={{ color: "var(--text-muted)" }}>Set values and calculate</p>
                </div>
              </Card>
            )}
          </div>
        </div>
      )}

      {!activeTool && (
        <Card style={{ textAlign: "center", opacity: 0.5, padding: "48px" }}>
          <div style={{ fontSize: "48px", marginBottom: "12px" }}>🔮</div>
          <p style={{ color: "var(--text-muted)" }}>Select a tool above to get started</p>
        </Card>
      )}
    </div>
  );
}

// ============================================================
// MAIN APP
// ============================================================
const MODULES = [
  { id: "self", emoji: "🚩", label: "Am I the\nRed Flag?" },
  { id: "partner", emoji: "🔍", label: "Are They a\nFlag?" },
  { id: "interest", emoji: "💘", label: "Do They\nLike Me?" },
  { id: "type", emoji: "🧠", label: "Relationship\nType?" },
  { id: "advanced", emoji: "🔮", label: "Advanced\nTools" },
];

export default function App() {
  const [activeModule, setActiveModule] = useState("self");
  const [brutal, setBrutal] = useState(false);

  return (
    <>
      <style>{globalStyles}</style>
      <div style={{ minHeight: "100vh", background: "var(--bg)" }}>
        {/* Hero Header */}
        <header style={{
          borderBottom: "1px solid var(--border)",
          background: "rgba(8,11,16,0.9)",
          backdropFilter: "blur(20px)",
          position: "sticky", top: 0, zIndex: 50,
        }}>
          <div style={{ maxWidth: "1200px", margin: "0 auto", padding: "16px 24px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
              <div style={{ width: "36px", height: "36px", borderRadius: "10px", background: "linear-gradient(135deg, #6366f1, #8b5cf6)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "18px" }}>🚩</div>
              <div>
                <div style={{ fontFamily: "'Syne', sans-serif", fontSize: "18px", fontWeight: "800", letterSpacing: "-0.5px" }}>FlagLogic AI</div>
                <div style={{ fontSize: "11px", color: "var(--text-muted)", marginTop: "-2px" }}>Relationship Intelligence Platform</div>
              </div>
            </div>
            <Toggle value={brutal} onChange={setBrutal} labelOff="Normal" labelOn="Brutal 🔥" colorOn="#ef4444" />
          </div>
        </header>

        {/* Nav */}
        <div style={{ borderBottom: "1px solid var(--border)", background: "var(--surface)" }}>
          <div style={{ maxWidth: "1200px", margin: "0 auto", padding: "0 24px", display: "flex", gap: "4px", overflowX: "auto" }}>
            {MODULES.map(m => (
              <button key={m.id} onClick={() => setActiveModule(m.id)}
                style={{
                  padding: "14px 18px", borderRadius: 0, border: "none", cursor: "pointer",
                  background: "transparent", fontFamily: "'Syne', sans-serif",
                  fontSize: "13px", fontWeight: "600", whiteSpace: "nowrap",
                  color: activeModule === m.id ? "#6366f1" : "rgba(255,255,255,0.4)",
                  borderBottom: `2px solid ${activeModule === m.id ? "#6366f1" : "transparent"}`,
                  transition: "all 0.2s",
                }}>
                <span style={{ marginRight: "6px" }}>{m.emoji}</span>
                {m.label.replace("\n", " ")}
              </button>
            ))}
          </div>
        </div>

        {/* Main Content */}
        <main style={{ maxWidth: "1200px", margin: "0 auto", padding: "32px 24px" }}>
          {brutal && (
            <div style={{ padding: "10px 16px", borderRadius: "8px", background: "rgba(239,68,68,0.08)", border: "1px solid rgba(239,68,68,0.2)", marginBottom: "20px", display: "flex", alignItems: "center", gap: "8px" }}>
              <span>🔥</span>
              <span style={{ fontSize: "13px", color: "#ef4444", fontWeight: "500" }}>Brutal Mode Active — Expect direct, unfiltered analysis</span>
            </div>
          )}

          {activeModule === "self" && <SelfAssessment brutal={brutal} setBrutal={setBrutal} />}
          {activeModule === "partner" && <PartnerAssessment brutal={brutal} />}
          {activeModule === "interest" && <InterestDetector brutal={brutal} />}
          {activeModule === "type" && <RelationshipClassifier brutal={brutal} />}
          {activeModule === "advanced" && <AdvancedTools brutal={brutal} />}
        </main>

        {/* Footer */}
        <footer style={{ borderTop: "1px solid var(--border)", padding: "20px 24px", textAlign: "center" }}>
          <p style={{ fontSize: "12px", color: "var(--text-muted)", maxWidth: "600px", margin: "0 auto" }}>
            ⚠️ This platform provides behavioral insights for reflection and entertainment. It is not psychological or medical advice.
          </p>
        </footer>
      </div>
    </>
  );
}
